import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSExample {
    public static void main(String[] args) {
        // Assume user input is obtained from a form submission or any other source
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Output the sanitized input
        System.out.println("Welcome, " + sanitizedInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
